# -*- coding: utf-8 -*-
import json, datetime, glob, sys
sys.stdout.reconfigure(encoding='utf-8')

TIMESTAMP = datetime.datetime.now().strftime("%Y-%m-%dT%H:%M")
BASE = "data/learn/"

# 先统计哪些模块 section 最少
files = sorted(glob.glob(BASE + '*.json'))
modules = []
for f in files:
    d = json.load(open(f, 'r', encoding='utf-8'))
    n = len(d.get('sections', []))
    modules.append((f, d.get('name',''), n))
modules.sort(key=lambda x: x[2])
print("Section最少的模块:")
for f, name, n in modules[:15]:
    print(f"  {n}sec  {name}")

